import mongoose from 'mongoose';
import dotenv from 'dotenv';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
dotenv.config({ path: path.resolve(__dirname, '../.env.local') });
dotenv.config({ path: path.resolve(__dirname, '../.env') });

const MONGO_URI = process.env.MONGO_URI;
if (!MONGO_URI) { console.error('MONGO_URI not found'); process.exit(1); }

const examCategorySchema = new mongoose.Schema({
  name: { type: String, required: true, trim: true },
  type: { type: String, enum: ['Central', 'State'], required: true },
  description: { type: String, trim: true }
}, { timestamps: true });

const examSchema = new mongoose.Schema({
  category: { type: mongoose.Schema.Types.ObjectId, ref: 'ExamCategory', required: true },
  name: { type: String, required: true, trim: true },
  code: { type: String, required: true, uppercase: true, trim: true },
  description: { type: String, trim: true },
  isActive: { type: Boolean, default: true },
  logo: { type: String }
}, { timestamps: true });

const examPatternSchema = new mongoose.Schema({
  exam: { type: mongoose.Schema.Types.ObjectId, ref: 'Exam', required: true },
  title: { type: String, required: true, trim: true },
  duration: { type: Number, required: true, min: 1 },
  totalMarks: { type: Number, required: true, min: 0 },
  negativeMarking: { type: Number, default: 0, min: 0 },
  sections: [{
    name: { type: String, required: true, trim: true },
    totalQuestions: { type: Number, required: true, min: 1 },
    marksPerQuestion: { type: Number, required: true, min: 0 },
    negativePerQuestion: { type: Number, default: 0, min: 0 },
    sectionDuration: { type: Number, min: 0 }
  }]
}, { timestamps: true });

const practiceTestSchema = new mongoose.Schema({
  examPattern: { type: mongoose.Schema.Types.ObjectId, ref: 'ExamPattern', required: true },
  title: { type: String, required: true, trim: true },
  slug: { type: String, lowercase: true, trim: true },
  totalMarks: { type: Number, required: true, min: 0 },
  duration: { type: Number, required: true, min: 1 },
  accessLevel: { type: String, enum: ['FREE', 'PRO'], default: 'FREE' },
  isPYQ: { type: Boolean, default: false },
  pyqYear: { type: Number, default: null },
  pyqShift: { type: String, default: null, trim: true },
  pyqExamName: { type: String, default: null, trim: true },
  publishedAt: { type: Date, default: Date.now },
  questions: [{
    questionText: { type: String, required: true },
    questionImage: { type: String, default: '' },
    options: [{ type: String, required: true }],
    optionImages: [{ type: String, default: '' }],
    correctAnswerIndex: { type: Number, required: true, min: 0 },
    explanation: { type: String, trim: true },
    section: { type: String, required: true, trim: true },
    tags: [{ type: String, trim: true }],
    difficulty: { type: String, enum: ['easy', 'medium', 'hard', 'mixed'], default: 'medium' }
  }]
}, { timestamps: true });

const ExamCategory = mongoose.models.ExamCategory || mongoose.model('ExamCategory', examCategorySchema);
const Exam = mongoose.models.Exam || mongoose.model('Exam', examSchema);
const ExamPattern = mongoose.models.ExamPattern || mongoose.model('ExamPattern', examPatternSchema);
const PracticeTest = mongoose.models.PracticeTest || mongoose.model('PracticeTest', practiceTestSchema);

const REA = 'General Intelligence';
const ENG = 'English Language';
const QA  = 'Quantitative Aptitude';
const GA  = 'General Awareness';

const KEY = [1, 4, 2, 2, 3, 1, 1, 3, 2, 3, 1, 3, 4, 4, 4, 2, 1, 2, 2, 1, 4, 2, 2, 2, 2, 1, 2, 2, 3, 2, 1, 1, 2, 1, 1, 2, 1, 1, 1, 2, 2, 1, 1, 1, 2, 1, 1, 2, 1, 1, 2, 1, 2, 2, 3, 3, 2, 2, 4, 2, 1, 2, 3, 3, 4, 1, 2, 3, 4, 2, 4, 2, 1, 3, 1, 2, 4, 1, 3, 4, 1, 1, 3, 2, 2, 1, 3, 3, 4, 1, 4, 2, 2, 2, 2, 3, 1, 2, 3, 4];
if (KEY.length !== 100) { console.error(`KEY length ${KEY.length}`); process.exit(1); }

const RAW = [
  { s: `General Intelligence`, q: `Brush is to Painting as Scissors is to _ ?`, o: [`Cutting`, `Stitching`, `Writing`, `Folding`], e: `A brush is used for painting. Created FromSDimatielarly, Created To Date Scissors are used for cutting. mm/dd/yyyTyh-u-s:,-c-o-r-rect option is (a). mm/dd/yyyy --:-- -- Search Clear` },
  { s: `General Intelligence`, q: `Which word does not belong to the group?`, o: [`Addition`, `Subtraction`, `Multiplication`, `Equation`], e: `An Equation is a matPhoesmt atical statement, not an opeLrEaNtiGonTH. So, Equation is(oMdadtroicnuelaotuiotn. ) Selection 24, 2026, 28, 2026, Thus, correct optSioimn iilsar(dP)a. per (Held on 28 Post 11:40:19 08:46:01` },
  { s: `General Intelligence`, q: `If MNO is related to ONM, then how is PQR related using the same logic?`, o: [`RPQ`, `RQP`, `QPR`, `PRQ`], e: `Given: If MNO is related to ONM. Logic: Position of letters are interchanged. For, MNO - ONM Similarly, PQR - ? So, PQR is related to RQP. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `A project is running behind schedule without affecting safety. What should the manager prioritize?`, o: [`Reduce safety measures to save time`, `Adjust non-essential features`, `Ignore the delay`, `Rush work without review`], e: `Given: A project is running behind schedule without affecting safety. Explanation: When a project is behind schedule, the manager should prioritize core requirements and adjust or postpone non-essential features. This helps recover time without compromising safety or quality, which should never be reduced. So, Adjust non-essential features should the manager prioritize. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `What comes next: 4, 6, 9, 13, 18, ___ ?`, o: [`22`, `23`, `24`, `25`], e: `Given: 4, 6, 9, 13, 18, ___ ? Logic: Numbers are increasing natural number from 2. 4+2=6 6+3=9 9 + 4 = 13 13 + 5 = 18 18 + 6 = 24 So, the missing term is 24. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `What will come next: Y, W, U, S, Q, ?`, o: [`O`, `P`, `N`, `M`], e: `Given: Y, W, U, S, Q, ? Logic: Letters are decreasing - 2 place. Y-2=W W-2=U U-2=S S-2=Q Q-2=O So, the missing term is O. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `Cat is to Whisker as Fish is to _ ?`, o: [`Fin`, `Scale`, `Tail`, `Gill`], e: `Given: Cat is to Whisker as Fish is to _ ? A cat has whiskers as a characteristic body part. Similarly, A fish has fins as a characteristic body part. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `If 4 workers take 8 days to complete a task, how many days will 8 workers take to complete the same task (same efficiency)?`, o: [`2 days`, `8 days`, `4 days`, `16 days`], e: `Given: If 4 workers take 8 days to complete a task. Solution: 4 workers × 8 days = 32 worker-days With 8 workers: 32 Days = = 4 8 So, 4 days will 8 workers take to complete the same task (same efficiency). Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `Mercury is to Planet as Moon is to:`, o: [`Star`, `Satellite`, `Asteroid`, `Comet`], e: `Given: Mercury is to Planet as Moon is to: Mercury is a planet. Similarly, The Moon is a satellite. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `In the given series: 4, 9, 14, 19, ___ ?`, o: [`22`, `23`, `24`, `25`], e: `Given: 4, 9, 14, 19, ___ ? Logic: Numbers are increasing + 5 place. 4+5=9 9 + 5 = 14 14 + 5 = 19 19 + 5 = 24 So, the missing term is 24. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `If 14 is to 196, then 23 is to _ ?`, o: [`529`, `506`, `489`, `552`], e: `Given: If 14 is to 196, then 23 is to _ ? Logic: 1st number2= 2nd number 142= 196 Similarly, 232= 529 Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `Which number from 18, 36, 54, 70, 72 is different from the others?`, o: [`36`, `54`, `70`, `72`], e: `18, 36, 54 and 72 are multiples of 18. 70 is not a multiple of 18. So, 70 is different from the others. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `If ★ = 4, ■ = 6, and ● = 3, what is ★ + ■ ?`, o: [`9`, `12`, `11`, `10`], e: `★ + ■ = 4 + 6 = 10. Option D.` },
  { s: `General Intelligence`, q: `Find the number that is different from the others.`, o: [`125`, `216`, `343`, `256`], e: `Now, we check each options. Option (a): 125 125 = 53 Option (b): 216 216 = 63 Option (c): 343 343 = 73 Option (d): 256 256 = 162 So, 256 number that is different from the others. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `Which of the following does not belong to the group?`, o: [`Rectangle`, `Rhombus`, `Parallelogram`, `Sphere`], e: `Rectangle, Rhombus and Parallelogram are 2-dimensional plane figures. Sphere is a 3-dimensional solid figure. So, Sphere is odd one out. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `Find the next number: 2, 4, 8, 14, 22, ___ ?`, o: [`30`, `32`, `34`, `36`], e: `Given: 2, 4, 8, 14, 22, ___ ? Logic: Numbers are increasing even number from 2. 2+2=4 4+4=8 8 + 6 = 14 14 + 8 = 22 22 + 10 = 32 So, the missing term is 32. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `Find the missing term: BDF, CEG, DFH, ___ ?`, o: [`EGI`, `EGH`, `EFI`, `FGI`], e: `Given: BDF, CEG, DFH, ___ ? Logic: Letters are increasing + 1 place. B + 1 = C, C + 1 = D, D + 1 = E D + 1 = E, E + 1 = F, F + 1 = G F + 1 = G, G + 1 = H, H + 1 = I So, the missing term is EGI. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `You see an elderly person struggling to cross the road. What is the best action to take?`, o: [`Ignore and move on`, `Help them cross safely`, `Tell others to help`, `Walk away`], e: `Given: You see an elderly person struggling to cross the road. Explanation: Helping an elderly person cross the road shows kindness, responsibility, and social awareness. It ensures their safety and reflects good civic behavior. So, Help them cross safely is the best action to take. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `An employee has two options to finish a report: Option A: Finish 70% with no errors Option B: Finish 100% with minor errors If completeness is more important than accuracy, which option should be chosen?`, o: [`Option A`, `Option B`, `Both are equal`, `Cannot be decided`], e: `Given: An employee has two options to finish a report: Option A: Finish 70% with no errors Option B: Finish 100% with minor errors If completeness is more important than accuracy. Explanation: Since completeness is more important than accuracy, finishing 100% of the report (even with minor errors) is preferred over completing only 70% without errors. So, Option B should be chosen. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `If X is the sister of Y and Y is the mother of Z, Z is the brother of A. How is Y related to A?`, o: [`Mother`, `Aunt`, `Sister`, `Son`], e: `Given: If X is the sister of Y and Y is the mother of Z, Z is the brother of A. From the given information blood relation diagram will be. So, Y is the mother of A. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `ABEF : BCFG :: DHKL : ?`, o: [`EILN`, `EIMN`, `EJMN`, `EILM`], e: `Given: ABEF : BCFG :: DHKL : ? Logic: Letters are increasing + 1 place. For, ABEF : BCFG A + 1 = B, B + 1 = C, E + 1 = F, F + 1 = G Similarly, DHKL : ? D + 1 = E, H + 1 = I, K + 1 = L, L + 1 = M So, DHKL : EILM Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `A classmate has forgotten their notebook. What should you do?`, o: [`Make fun of them`, `Lend them help or notes`, `Ignore them`, `Complain to the teacher`], e: `Given: A classmate has forgotten their notebook. Explanation: Helping a classmate by lending notes or offering help shows kindness, cooperation, and teamwork. It supports a positive learning environment, whereas making fun of them or ignoring the situation is unhelpful. So, Lend them help or notes should you do. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `If △ = 2, ◇ = 4, and ■ = 6, what is △ × ◇ + ■ ?`, o: [`12`, `14`, `16`, `18`], e: `△ × ◇ + ■ = 2 × 4 + 6 = 8 + 6 = 14. Option B.` },
  { s: `General Intelligence`, q: `If \`+' means \`×', \`×' means \`-', \`-' means \`÷', and \`÷' means \`+', then find the value of: 8 + 6 × 2 - 4 ÷ 2 = ?`, o: [`50`, `49.5`, `48.5`, `49`], e: `Given: 8 + 6 × 2 - 4 ÷ 2 = ? Given Sign+× - ÷ New Sign × - ÷+ Using BODMAS rule. Symbol [], , () Operation preference wise Brackets (power), (root), of Orders, of ÷ Division × + Multiplication - Addition Subtraction New equation: 8 × 6 - 2 ÷ 4 + 2 = ? 8 × 6 - 0.5 + 2 = ? 48 - 0.5 + 2 = ? 50 - 0.5 = ? ? = 49.5 Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `If 7 is to 49, then 15 is to _ ?`, o: [`210`, `225`, `180`, `105`], e: `Given: If 7 is to 49, then 15 is to _ ? Logic: 1st number2= 2nd number 72= 49 Similarly, 152= 225 Thus, correct option is (b).` },
  { s: `General Awareness`, q: `Which of the following is an example of a macroeconomic indicator?`, o: [`Inflation rate`, `Price of a product`, `Demand for a brand`, `Company profit`], e: `The correct answer is (A) Inflation rate Explanation: · Macroeconomics studies the economy as a whole rather than individual markets. · Indicators like inflation, GDP, and unemployment rates provide a broad view of national economic health. Information Booster: · Inflation represents the rate at which the general level of prices for goods and services is rising. Additional Knowledge: · Price of a product (Option B): This is a microeconomic focus as it deals with individual goods. · Demand for a brand (Option C): Related to specific consumer behavior (Microeconomics). · Company profit (Option D): Analyzes the performance of an individual firm (Microeconomics).` },
  { s: `General Awareness`, q: `What determines the number of births per 1000 people in a year?`, o: [`Fertility rate`, `Birth rate`, `Mortality rate`, `Migration rate`], e: `The correct answer is (B) Birth rate Explanation: · The Crude Birth Rate (CBR) is the number of live births occurring among the population of a given geographical area during a given year, per 1,000 mid-year total population. Information Booster: · Natural increase in population is calculated as: Birth Rate - Death Rate. Additional Knowledge: · Fertility rate (Option A): The average number of children a woman would have in her childbearing years. · Mortality rate (Option C): The number of deaths per 1000 people.` },
  { s: `General Awareness`, q: `What is the primary objective of the Skill India Mission?`, o: [`Promote entrepreneurship`, `Develop vocational skills among youth`, `Provide housing`, `Improve health services`], e: `The correct answer is (B) Develop vocational skills among youth Explanation: · Launched in 2015, it aims to create convergence across sectors and states in terms of skill training activities. · Its major component is the Pradhan Mantri Kaushal Vikas Yojana (PMKVY). Information Booster: · National Skill Development Corporation (NSDC) is a key implementation body. Additional Knowledge: · Health services (Option D): This is the focus of the National Health Mission (NHM).` },
  { s: `General Awareness`, q: `The FIFA World Cup is usually held every:`, o: [`2 years`, `3 years`, `4 years`, `5 years`], e: `The correct answer is (C) 4 years Explanation: · The FIFA World Cup has been held every four years since the inaugural tournament in 1930. · Exceptions occurred in 1942 and 1946 due to World War II. Information Booster: · The 2026 World Cup will be the first to be hosted by three nations: USA, Mexico, and Canada. Additional Knowledge: · 2 years (Option A): Most major multi-sport events like the Olympics or World Cups follow a 4-year cycle to allow for qualifications.` },
  { s: `General Awareness`, q: `What is the main reason for declining population growth in developed countries?`, o: [`High birth rate`, `Low fertility rate`, `High death rate`, `High migration`], e: `The correct answer is (B) Low fertility rate Explanation: · Many developed nations have a Total Fertility Rate (TFR) below 2.1, which is the replacement level. · Factors like late marriages and high cost of living contribute to fewer births. Information Booster: · Countries like Japan and South Korea are currently facing severe demographic crises due to low fertility rates. Additional Knowledge: · High death rate (Option C): Developed countries usually have low death rates due to advanced healthcare.` },
  { s: `General Awareness`, q: `Which scheme focuses on improving urban water supply and sewerage systems?`, o: [`AMRUT`, `PMJDY`, `PMFBY`, `Ujjwala Yojana`], e: `The correct answer is (A) AMRUT Explanation: · AMRUT stands for Atal Mission for Rejuvenation and Urban Transformation. · It ensures that every household has access to a tap with an assured supply of water and a sewerage connection. Information Booster: · AMRUT 2.0 was launched in 2021 to make cities 'water secure'. Additional Knowledge: · PMJDY (Option B): Jan Dhan Yojana for financial inclusion. · PMFBY (Option C): Fasal Bima Yojana for crop insurance.` },
  { s: `General Awareness`, q: `Which scheme focuses on providing clean cooking fuel (LPG) to rural households?`, o: [`Pradhan Mantri Ujjwala Yojana`, `Pradhan Mantri Awas Yojana`, `Jan Dhan Yojana`, `Skill India`], e: `The correct answer is (A) Pradhan Mantri Ujjwala Yojana Explanation: · Launched in 2016, PMUY provides LPG connections to women from Below Poverty Line (BPL) households. · It aims to reduce respiratory issues caused by traditional indoor cooking smoke. Information Booster: · Ujjwala 2.0 was launched in 2021 to provide free first refills and stoves. Additional Knowledge: · PM Awas Yojana (Option B): Focuses on affordable housing. · Jan Dhan Yojana (Option C): Focuses on universal financial inclusion.` },
  { s: `General Awareness`, q: `India has developed the Sittwe Port as part of the KaladCaonpMyruiglthit-M©o2d0a2l6PrAodjedcat2i4n7:`, o: [`Bangladesh`, `Myanmar`, `Sri Lanka`, `Thailand`], e: `The correct answer is (B) Myanmar Explanation: · Sittwe Port is located in the Rakhine State of Myanmar. · The project connects Kolkata with Sittwe, providing an alternative route to India's North-East region. Information Booster: · The project involves sea, river (Kaladan), and road transport. Additional Knowledge: · Sri Lanka (Option C): India is involved in the development of the Kankesanthurai Port here.` },
  { s: `General Awareness`, q: `The Chhatri in Rajput architecture refers to:`, o: [`Dome-shaped pavilion`, `Stone pillar`, `Balcony window`, `Courtyard`], e: `The correct answer is (A) Dome-shaped pavilion Explanation: · Chhatris are elevated, dome-shaped pavilions used as elements in Indian architecture, particularly Rajasthani. · They are often built as memorials at the cremation sites of royalty. Information Booster: · The term 'Chhatri' literally means umbrella, reflecting the shape of the dome. Additional Knowledge: · Balcony window (Option C): Often referred to as 'Jharokha' in Rajput architecture.` },
  { s: `General Awareness`, q: `What is the name of the development bank created by the Asian Infrastructure Investment Bank initiative?`, o: [`AIIB`, `ADB`, `IMF`, `NDB`], e: `The correct answer is (A) AIIB Explanation: · The AIIB is a multilateral development bank that started operations in 2016. · It focuses on financing infrastructure projects in the Indo-Pacific region. Information Booster: · AIIB is headquartered in Beijing, China. Additional Knowledge: · NDB (Option D): New Development Bank, established by the BRICS countries.` },
  { s: `General Awareness`, q: `Which Indian organization developed the COVAXIN vaccine for COVID-19?`, o: [`Serum Institute of India`, `Bharat Biotech`, `Panacea Biotec`, `Biological E`], e: `The correct answer is (B) Bharat Biotech Explanation: · COVAXIN was developed by Bharat Biotech in collaboration with the Indian Council of Medical Research (ICMR). · It is an inactivated virus-based vaccine. Information Booster: · It was India's first indigenous vaccine against COVID-19. Additional Knowledge: · Serum Institute of India (Option A): Manufactured Covishield (developed by Oxford-AstraZeneca).` },
  { s: `General Awareness`, q: `Which of the following species is endemic to the Eastern Himalayas?`, o: [`Red Panda`, `Nilgiri Tahr`, `Asiatic Lion`, `Great Indian Bustard`], e: `The correct answer is (A) Red Panda Explanation: · The Red Panda is found in the high-altitude temperate forests of the Eastern Himalayas (Sikkim, Arunachal Pradesh, etc.). · It is the state animal of Sikkim. Information Booster: · The Red Panda is listed as 'Endangered' on the IUCN Red List. Additional Knowledge: · Nilgiri Tahr (Option B): Endemic to the Western Ghats. · Asiatic Lion (Option C): Found only in Gir National Park, Gujarat. · Great Indian Bustard (Option D): Found in the arid grasslands of Rajasthan and Gujarat.` },
  { s: `General Awareness`, q: `Which organization publishes the annual Global Gender Gap Report?`, o: [`World Economic Forum (WEF)`, `International Monetary Fund (IMF)`, `World Bank`, `United Nations Development Programme (UNDP)`], e: `The correct answer is (A) World Economic Forum (WEF) Explanation: · The Global Gender Gap Report benchmarks gender-based gaps across four dimensions: Economy, Education, Health, and Politics. · It was first published in 2006. Information Booster: · WEF is headquartered in Cologny, Switzerland. Additional Knowledge: · UNDP (Option D): Publishes the Human Development Report (HDR).` },
  { s: `General Awareness`, q: `Which of the following minerals is mainly found in the ACroapvyarlilgi hretg©io2n0o2f6RAadjadsat2h4a7n?`, o: [`Copper`, `Petroleum`, `Coal`, `Natural gas`], e: `The correct answer is (A) Copper Explanation: · The Aravalli range in Rajasthan is rich in non-ferrous minerals, especially copper. · Famous mines include the Khetri copper belt in the Jhunjhunu district. Information Booster: · Rajasthan is the second-largest producer of copper in India after Madhya Pradesh. Additional Knowledge: · Petroleum (Option B): Found in the Barmer basin, not typically associated with the mountainous Aravalli rock formations.` },
  { s: `General Awareness`, q: `What is a key feature of the Bharatiya Nagarik Suraksha Sanhita (BNSS) related to criminal procedure?`, o: [`It abolishes all criminal courts`, `It replaces the Code of Criminal Procedure (CrPC), 1973`, `It removes police investigation powers`, `It bans digital evidence`], e: `The correct answer is (B) It replaces the Code of Criminal Procedure (CrPC), 1973 Explanation: · The BNSS was enacted to replace the colonial-era CrPC to modernize the criminal justice system. · It focuses on faster trials and the mandatory use of technology in investigations. Information Booster: · The BNSS, along with BNS (replaces IPC) and BSA (replaces Evidence Act), came into effect on July 1, 2024. Additional Knowledge: · Digital Evidence (Option D): BNSS actually legally validates and encourages the use of digital evidence.` },
  { s: `General Awareness`, q: `Fill in the blank: India's Chandrayaan-3 mission successfully landed near the Moon's ______ pole.`, o: [`Northern`, `Southern`, `Eastern`, `Western`], e: `The correct answer is (B) Southern Explanation: · On August 23, 2023, India became the first country to land a spacecraft near the lunar south pole. · The landing site was officially named 'Shiv Shakti Point'. Information Booster: · The mission used the Vikram lander and the Pragyan rover. Additional Knowledge: · Northern (Option A): Most previous missions from other countries landed in the equatorial or northern regions.` },
  { s: `General Awareness`, q: `Fill in the blank: The phenomenon in which the Moon passes directly between the Earth and the Sun but does not completely cover it is called a ______.`, o: [`Solar eclipse`, `Transit`, `Lunar eclipse`, `Conjunction`], e: `The correct answer is (A) Solar eclipse Explanation: · A solar eclipse occurs when the Moon moves between the Sun and Earth, casting a shadow on Earth. · An annular solar eclipse specifically refers to when the Moon is too far away to completely cover the Sun, creating a "ring of fire". Information Booster: · The Sun's corona is only visible to the naked eye during a total solar eclipse. Additional Knowledge: · Transit (Option B): When a smaller body (like Mercury or Venus) passes in front of a much larger body. · Lunar eclipse (Option C): When the Earth comes between the Sun and the Moon. · Conjunction (Option D): When two celestial objects appear close to each other in the sky from Earth's perspective.` },
  { s: `General Awareness`, q: `Hindustani classical music developed mainly in:`, o: [`Northern India`, `Southern India`, `Eastern India`, `Western India`], e: `The correct answer is (A) Northern India Explanation: · Hindustani classical music is the traditional music of Northern India, North-West, and Central India. · It was influenced by Persian and Sufi musical traditions over centuries. Information Booster: · Carnatic music is the classical music tradition associated with Southern India. Additional Knowledge: · Southern India (Option B): Home to the Melakarta system of Carnatic music.` },
  { s: `General Awareness`, q: `Who wrote the famous book "The Discovery of India"?`, o: [`Jawaharlal Nehru`, `Rabindranath Tagore`, `R.K. Narayan`, `Mulk Raj Anand`], e: `The correct answer is (A) Jawaharlal Nehru Explanation: · Nehru wrote this book during his imprisonment at Ahmednagar Fort (1942­1945) for participating in the Quit India Movement. · It provides a historical and cultural analysis of India from ancient times to the British Raj. Information Booster: · Nehru was the first and longest-serving Prime Minister of India. Additional Knowledge: · Rabindranath Tagore (Option B): Wrote the national anthem and 'Gitanjali'.` },
  { s: `General Awareness`, q: `Which of the following is measured using an anemometer?`, o: [`Temperature`, `Wind speed`, `Atmospheric pressure`, `Humidity`], e: `The correct answer is (B) Wind speed Explanation: · An anemometer is an instrument used to measure the speed of wind. · Cup anemometers are the most common type used in weather stations. Information Booster: · A wind vane is used to determine the direction of the wind. Additional Knowledge: · Temperature (Option A): Measured by a Thermometer. · Atmospheric pressure (Option C): Measured by a Barometer. · Humidity (Option D): Measured by a Hygrometer.` },
  { s: `General Awareness`, q: `Which ministry is responsible for implementing the Make in India initiative?`, o: [`Ministry of Commerce and Industry`, `Ministry of Finance`, `Ministry of Defence`, `Ministry of External Affairs`], e: `The correct answer is (A) Ministry of Commerce and Industry Explanation: · Make in India was launched in 2014 to transform India into a global manufacturing hub. · It is managed by the Department for Promotion of Industry and Internal Trade (DPIIT) under this ministry. Information Booster: · The initiative's logo is a lion made of gears, symbolizing strength and manufacturing. Additional Knowledge: · Ministry of Finance (Option B): Handles the union budget and taxation policies.` },
  { s: `General Awareness`, q: `Which novel by Kiran Desai won the Booker Prize?`, o: [`The Inheritance of Loss`, `The God of Small Things`, `Midnight's Children`, `The White Tiger`], e: `The correct answer is (A) The Inheritance of Loss Explanation: · Kiran Desai won the Man Booker Prize in 2006 for this novel. · The book explores themes of identity, globalization, and colonialism. Information Booster: · Kiran Desai is the daughter of novelist Anita Desai. Additional Knowledge: · The God of Small Things (Option B): Won by Arundhati Roy in 1997. · Midnight's Children (Option C): Won by Salman Rushdie in 1981. · The White Tiger (Option D): Won by Aravind Adiga in 2008.` },
  { s: `General Awareness`, q: `Who acts as the constitutional head of the Union Government of India?`, o: [`Prime Minister`, `President`, `Vice-President`, `Chief Justice`], e: `The correct answer is (B) President Explanation: · Under Article 53 of the Constitution, the executive power of the Union is vested in the President. · He/she is the nominal or ceremonial head of the state. Information Booster: · The President is also the Supreme Commander of the Indian Armed Forces. Additional Knowledge: · Prime Minister (Option A): Acts as the real executive head (De facto head).` },
  { s: `General Awareness`, q: `In which year were the first Commonwealth Games held?`, o: [`1930`, `1948`, `1951`, `1960`], e: `The correct answer is (A) 1930 Explanation: · The first Commonwealth Games, then known as the British Empire Games, were held in Hamilton, Canada. · 11 countries participated in 6 sports. Information Booster: · India first participated in the Commonwealth Games in 1934 (London). Additional Knowledge: · 1951 (Option C): The first Asian Games were held in New Delhi.` },
  { s: `General Awareness`, q: `The Amaravati school of sculpture is mainly associated with:`, o: [`Buddhist art`, `Mughal art`, `Gupta art`, `Rajput art`], e: `The correct answer is (A) Buddhist art Explanation: · The Amaravati school developed in the Vengi region (Andhra Pradesh) under the Satavahanas. · It is famous for relief sculptures on white marble depicting Jataka tales. Information Booster: · The school is known for its 'narrative' style of sculpture. Additional Knowledge: · Mughal art (Option B): Primarily focuses on architecture and miniature painting.` },
  { s: `Quantitative Aptitude`, q: `√5 + √7 is classified as:`, o: [`Integer`, `Irrational`, `Rational`, `Natural Number`], e: `Sum of two distinct irrational numbers (√5 and √7) is irrational. Option B.` },
  { s: `Quantitative Aptitude`, q: `A car covers 120 km with a speed of 40 km/h and then another 120 km with a speed of 60 km/h. What is the overall average speed of the car?`, o: [`48 km/h`, `50 km/h`, `52 km/h`, `45 km/h`], e: `Given: Distance 1 = 120 km, Speed 1 (S1) = 40 km/h Distance 2 = 120 km, Speed 2 (S2) = 60 km/h Formula Used: When distances are equal, Average Speed = 2 × S1 × S2 S1 + S2 Solution: Substitute the speeds into the formula: 2 × 40 × 60 A verage Speed = 40 + 60 4800 Average Speed = 100 Average Speed = 48 km/h So the correct answer is (a).` },
  { s: `Quantitative Aptitude`, q: `A solid rectangular block has dimensions 6 cm × 4 cm × 3 cm. Find its total surface area.`, o: [`96 cm²`, `108 cm²`, `112 cm²`, `120 cm²`], e: `Given: Length (l) = 6 cm. Breadth (b) = 4 cm. Height (h) = 3 cm. Formula Used: Total Surface Area (TSA) of a cuboid = 2(lb + bh + hl) Solution: TSA = 2 × (6 × 4 + 4 × 3 + 3 × 6) TSA = 2 × (24 + 12 + 18) TSA = 2 × (54) TSA = 108 cm2 So the correct answer is (b).` },
  { s: `Quantitative Aptitude`, q: `A train 300 m long passes a telegraph pole in 15 seconds. What is its speed?`, o: [`60 km/h`, `72 km/h`, `54 km/h`, `90 km/h`], e: `Given: Length of train = 300 m. Time taken to pass pole = 15 seconds Formula Used: Distance S peed in m/s = T ime 18 Speed in km/h = Speed inm/s × 5 Solution: 300 Speed = = 20m/s 15 18 Speed = 20 × = 4 × 18 = 72km/h 5 So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `A train 250 meters long is traveling at a speed of 90 km/h. How long will it take to pass a bridge 200 meters long?`, o: [`15 seconds`, `20 seconds`, `18 seconds`, `22 seconds`], e: `Given: Length of train = 250 m Length of bridge = 200 m Speed of train = 90 km/h Formula Used: Total Distance = Length of train + Length of bridge 5 S peed in m/s = Speed in km/h × 18 Time = Total Distance Speed Solution: Total Distance = 250 + 200 = 450 m 5 S peed = 90 × = 5 × 5 = 25m/s 18 450 T ime = = 18seconds 25 So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `A bowl in the shape of a hemisphere is completely filled with liquid. The liquid is then poured into a cylindrical glass having the same base radius and a height equal to its radius. What fraction of the cylinder is filled?`, o: [`1/2`, `3/4`, `2/3`, `1/3`], e: `Given: Bowl (hemisphere) is filled with liquid. Liquid is poured into a cylinder. Radius of cylinder = Radius of hemisphere = r. Height of cylinder (h) = r. Formula Used: 2 Volume of hemisphere = × × r3 3 Volume of cylinder = × r2 × h Solution: 2 Volume of liquid in hemisphere = × × r3 3 Volume of the cylindrical glass = × r2 × (r) = × r3 Fraction of cylinder filled = Volume of liquid Volume of cylinder F raction = 2 × × r3 3 × r3 2 F raction = 3 So the correct answer is (c).` },
  { s: `Quantitative Aptitude`, q: `A store gives two successive discounts of 15% and 10%. What is the net discount percentage?`, o: [`25%`, `23.5%`, `24%`, `22.5%`], e: `Given: Successive discounts are 15% and 10%. Formula Used Net Discount = X + Y - X × Y 100 Solution: Substitute X = 15 and Y = 10 into the formula 15 × 10 Net Discount = 15 + 10 - 100 150 Net Discount = 25 - 100 Net Discount = 25 - 1.5 = 23.5% So the correct answer is (b).` },
  { s: `Quantitative Aptitude`, q: `A tangent PQ at point P of a circle with radius 5 cm meets a line through the center O at point Q such that OQ = 13 cm. What is the length of the tangent PQ?`, o: [`8 cm`, `12 cm`, `14 cm`, `10 cm`], e: `Given: Radius (OP) = 5 cm. Distance from center to point Q (OQ) = 13 cm. Tangent PQ meets the radius at point P. Formula Used: The radius to the point of tangency is perpendicular to the tangent line, meaning angle OPQ is 90 degrees. Pythagoras Theorem: Hypotenuse2 = Base2 + Perpendicular2. Solution: In the right-angled triangle OPQ: OQ2 = OP2 + PQ2. 132 = 52 + PQ2. 169 = 25 + PQ2. PQ2 = 169 - 25 = 144. PQ = 144 = 12 cm. So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `Sita earns 18,000 per month, and Gita earns 2,40,000 per annum. If both spend 12,000 per month, what is the ratio of their savings?`, o: [`5:6`, `4:3`, `2:3`, `3:4`], e: `Given: Sita's monthly income = 18,000 Gita's annual income = 2,40,000 Monthly expenditure for both = 12,000 Formula Used: Monthly Income = Annual Income 12 Savings = Income - Expenditure Solution: Gita's monthly income = 240000 = 20,000 12 Sita's savings = 18000 - 12000 = 6,000 Gita's savings = 20000 - 12000 = 8,000 Ratio of their savings = 6000 : 8000 Simplify by dividing by 2000: Ratio = 3 : 4 So the correct answer is (d).` },
  { s: `Quantitative Aptitude`, q: `Fill in the blank: Every non-terminating, non-repeating decimal is classified as a(n) ________ number.`, o: [`Rational`, `Irrational`, `Integer`, `Whole`], e: `Given: A non-terminating, non-repeating decimal. Formula Used: Definitions of rational and irrational numbers. Solution: Rational numbers can be expressed as a fraction of two integers and their decimal expansions are either terminating or repeating. Irrational numbers cannot be expressed as a simple fraction, and their decimal expansions are non-terminating and non-repeating. Therefore, the number is classified as an irrational number. So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `What is the unit digit (ones place) of the square of 73?`, o: [`9`, `3`, `6`, `1`], e: `Given: Number = 73. Formula Used: The unit digit of the square of a number is completely determined by the square of its unit digit. Solution: The unit digit of 73 is 3. Square the unit digit: 3 × 3 = 9. Therefore, the unit digit of the square of 73 is 9. So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `Y alone can finish a piece of work in 20 days, but with X's help, they complete it in 12 days. In how many days can X alone finish the work?`, o: [`24 days`, `30 days`, `25 days`, `28 days`], e: `Given: Time taken by Y alone = 20 days. Time taken by X and Y together = 12 days. Formula Used: 11 1 + = X Y X + Y (together) Solution: Let the time taken by X alone be x days. 11 1 + = x 20 12 11 1 =- x 12 20 15 3 =- x 60 60 12 1 = = x 60 30 x = 30 days So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `The perimeter of a triangle is 36 cm. If two sides are 12 cm and 15 cm, what is the length of the third side?`, o: [`11 cm`, `8 cm`, `9 cm`, `10 cm`], e: `Given: Perimeter of triangle = 36 cm. First side = 12 cm. Second side = 15 cm. Formula Used: Perimeter of a triangle = Sum of all three sides = Side 1 + Side 2 + Side 3 Solution: Let the third side be x. 36 = 12 + 15 + x 36 = 27 + x x = 36 - 27 x = 9 cm So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `A woman's salary was increased by 15% to 46,000. What was her original salary?`, o: [`38,000`, `42,000`, `40,000`, `45,000`], e: `Given: New Salary = 46,000 Percentage increase = 15% Formula Used: New Salary = Original Salary × (1 + Increase Percentage ) 100 Solution: Let Original Salary be X 15 X × (1 + ) = 46000 100 X × 1.15 = 46000 X= 46000 1.15 X = 40000 So the correct answer is (c).` },
  { s: `Quantitative Aptitude`, q: `A merchant buys a bag for 600 and sells it at a profit of 15%. What is the selling price?`, o: [`660`, `650`, `720`, `690`], e: `Given: Cost Price (CP) = 600 Profit percentage = 15% Formula Used: Selling Price (SP) = CP + (Profit % × CP) Solution: Profit amount = 15% of 600 15 Profit = × 600 = 15 × 6 = 90 100 Selling Price = 600 + 90 = 690 So the correct answer is (d)` },
  { s: `Quantitative Aptitude`, q: `A dealer allows two successive discounts of 15% and 20% on a laptop marked at 40,000. If he still earns a profit of 25%, what is the cost price of the laptop?`, o: [`21,760`, `22,500`, `21,500`, `20,800`], e: `Given: Marked Price (MP) = 40,000 Successive discounts = 15% and 20% Profit percentage = 25% Formula Used: Selling Price (SP) = MP × (1 - D1 × (1 - D2 ) ) 100 100 Cost Price (CP) = SP 1+ P rof it 100 Solution: SP = 40000 × (1 - 0.15) × (1 - 0.20) SP = 40000 × 0.85 × 0.80 SP = 40000 × 0.68 = 27,200 Since Profit is 25%, SP = 125% of CP 27200 CP = 1.25 CP = 21,760 So the correct answer is (a).` },
  { s: `Quantitative Aptitude`, q: `A party hat is shaped like a cone having a radius of 7 cm and a height of 15 cm. What is its volume (in cm³)? (Take =22/7)`, o: [`750 cm³`, `770 cm³`, `790 cm³`, `810 cm³`], e: `Given: Radius of cone (r) = 7 cm Height of cone (h) = 15 cm 22 = 7 Formula Used: 1 Volume of a cone = × × r2 × h 3 Solution: 1 22 V olume = × × 7 × 7 × 15 37 Volume = 1 × 22 × 7 × 15 3 Volume = 22 × 7 × 5 = 154 × 5 Volume = 770cm3 So the correct answer is (b).` },
  { s: `Quantitative Aptitude`, q: `If the profit on a gadget is 20% and the cost price is 1,200, find the selling price.`, o: [`1,400`, `1,420`, `1,440`, `1,480`], e: `Given: Cost Price (CP) = 1,200. Profit percentage = 20%. Formula Used: Selling Price (SP) = CP × (1 + P rof it ) 100 Solution: 20 SP = 1200 × (1 + ) 100 SP = 1200 × 1.20 SP = 1,440 So the correct answer is (c).` },
  { s: `Quantitative Aptitude`, q: `The average of six numbers is 32. If one number is removed, the average becomes 30. What is the removed number?`, o: [`38`, `40`, `44`, `42`], e: `Given: Initial Average of 6 numbers = 32 New Average of 5 numbers = 30 Formula Used: Sum of numbers = Average × Number of items Removed Number = Initial Sum - New Sum Solution: Initial Sum = 6 × 32 = 192 New Sum = 5 × 30 = 150 Removed Number = 192 - 150 = 42 So the correct answer is (d).` },
  { s: `Quantitative Aptitude`, q: `A container holds 45.5 liters of oil. If a leak causes 2/7 of the oil to spill, how much oil remains in the container (in liters)?`, o: [`13 L`, `32.5 L`, `31.5 L`, `34.25 L`], e: `Given: Total oil = 45.5 liters. 2 Fraction of oil spilled = 7 Formula Used: Remaining Fraction = 1 - Fraction Spilled Remaining Oil = Total Oil × Remaining Fraction Solution: 25 Remaining fraction = 1 - = 57 7 Remaining Oil = 45.5 × 7 Remaining Oil = 6.5 × 5 = 32.5 Liters So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `A student scored 115 marks in an exam and failed by 20 marks. If the pass percentage is 45%, what was the maximum mark?`, o: [`250`, `350`, `280`, `300`], e: `Given: Marks scored = 115 Failed by = 20 marks Pass percentage = 45% Formula Used: Pass Marks = Marks Scored + Shortfall Marks Maximum Marks = Pass Marks × 100 Pass Percentage Solution: Pass Marks = 115 + 20 = 135. Let Maximum Marks be M. 45% of M = 135. 45 × M = 135 100 M= 135 × 100 45 M = 3 × 100 = 300 So the correct answer is (d)` },
  { s: `Quantitative Aptitude`, q: `A person drives to the station at 30 km/h and reaches 10 minutes late. If he drives at 50 km/h, he reaches 6 minutes early. What is the distance to the station?`, o: [`15 km`, `20 km`, `25 km`, `30 km`], e: `Given: Speed 1 (S1) = 30 km/h, Time 1 (T1) = 10 minutes late. Speed 2 (S2) = 50 km/h, Time 2 (T2) = 6 minutes early. Formula Used: Distance = S1 × S2 × Time Difference in hours. S2 - S1 Solution: Time difference = 10 minutes late + 6 minutes early = 16 minutes 16 4 T ime difference in hours = = hours 60 15 Distance = 30 × 50 4 × 50 - 30 15 1500 4 Distance = × 20 15 4 Distance = 75 × 15 Distance = 5 × 4 Distance = 20km So the correct answer is (b).` },
  { s: `Quantitative Aptitude`, q: `If 8 workers can complete a project in 15 days, how many days will 10 workers take to finish the same project?`, o: [`12 days`, `10 days`, `14 days`, `16 days`], e: `Given Workers (M1) = 8 Days (D1) = 15 Workers (M2) = 10 Formula Used M1 × D1 = M2 × D2 Solution Substitute the values into the formula: 8 × 15 = 10 × D2 120 = 10 × D2 120 D2 = = 12 days 10 So the correct answer is (a).` },
  { s: `Quantitative Aptitude`, q: `Find the time if 5,000 amounts to 6,500 at 10% simple interest.`, o: [`2.5 years`, `3.5 years`, `3 years`, `4 years`], e: `Given: Principal (P) = 5,000 Amount (A) = 6,500 Rate (R) = 10% per annum Formula Used: Simple Interest (SI) = Amount - Principal P ×R×T SI = 100 Solution: SI = 6500 - 5000 = 1,500. Using the SI formula: 5000 × 10 × T 1500 = 100 1500 = 500 × T 1500 T= 500 T = 3 years So the correct answer is (c).` },
  { s: `Quantitative Aptitude`, q: `4.20 as a mixed number is:`, o: [`4 1/5`, `4 1/4`, `4 2/5`, `4 1/2`], e: `4.20 = 4 + 0.20 = 4 + 20/100 = 4 + 1/5 = 4 1/5. Option A.` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: The tourists admired (1) / the furnitures (2) / displayed in the (3) / heritage palace (4).`, o: [`The tourists admired (1)`, `the furnitures (2)`, `displayed in the (3)`, `heritage palace. (4)`], e: `The correct option is (B). Explanation Part (2) of the sentence contains an error. The word "furnitures" is grammatically incorrect because "furniture" is an uncountable noun. Uncountable nouns do not have a plural form and cannot be used with 's' at the end to indicate plurality. Grammatical Rule used: Nouns such as furniture, scenery, luggage, poetry, advice, information, and machinery are uncountable. They are always used in the singular form. To express a plural sense, we use phrases like "pieces of furniture" or "items of furniture," but the word "furnitures" never exists in standard English. Example: I bought some new furniture (not furnitures) for my office. Information Booster: Always check for nouns that are inherently singular in form despite representing a collection of items. U` },
  { s: `English Language`, q: `Fill in the blank with the most appropriate option: His new painting is __ than his previous one.`, o: [`impressive`, `impression`, `most impressive`, `more impressive`], e: `The correct option is (D) more impressive. Explanation The sentence involves a comparison between two things: the "new painting" and the "previous one." When comparing two specific entities, we must use the comparative degree of the adjective. For multi-syllable adjectives like "impressive," the comparative degree is formed by adding "more" before the word. Example: This book is more interesting than the last one. Meanings of other options: Option A: "impressive" is the positive degree, used when no comparison is being made. Option B: "impression" is a noun, not an adjective, and cannot modify the painting in this context. Option C: "most impressive" is the superlative degree, used when comparing three or more things. Information Booster: The presence of the word "than" is a clear indicato` },
  { s: `English Language`, q: `Arrange the passage correctly: (1) Transfer the clothes to the dryer or hang them to dry. (2) Add detergent and load the clothes into the washing machine. (3) Set the wash cycle and start the machine. (4) Sort the clothes by colour and fabric type.`, o: [`4-2-3-1`, `2-4-1-3`, `3-4-2-1`, `4-3-2-1`], e: `The correct option is (A). Explanation The sentences describe the chronological process of washing clothes. The logical flow is as follows: Sentence (4) is the opening step, as sorting clothes must happen before they are put in a machine. Sentence (2) follows, where the sorted clothes are loaded and detergent is added. Sentence (3) describes the action of starting the machine once it is loaded. Sentence (1) is the final step, involving drying the clothes after the wash cycle is complete. The sequence 4-2-3-1 maintains a perfect logical and temporal order of events. So the correct answer is (a)` },
  { s: `English Language`, q: `Fill in the blank with the most appropriate adverb. She finished the assignment _____ than her classmates had anticipated.`, o: [`quick`, `quickly`, `more quickly`, `most quickly`], e: `The correct option is (C) more quickly. Explanation The blank requires an adverb to modify the verb "finished." Since the sentence uses "than" to compare her performance with the expectations of her classmates, we must use the comparative degree of the adverb. Adverbs ending in "-ly" typically form their comparative degree using "more." Example: He spoke more loudly than usual. Meanings of other options: Option A: "quick" is an adjective, not an adverb. Option B: "quickly" is the positive degree of the adverb, used when no comparison is made. Option D: "most quickly" is the superlative degree, used for comparisons involving more than two entities or extremes. Information Booster: In formal English, always distinguish between adjectives (describing nouns) and adverbs (describing verbs). Use` },
  { s: `English Language`, q: `Fill in the blank with the most appropriate option: The principal expects the application to be __________ before the deadline.`, o: [`submits`, `submit`, `submitting`, `submitted`], e: `The correct option is (D) submitted. Explanation The sentence is in the passive voice within an infinitive phrase ("to be + past participle"). The subject of the action is the application, which does not perform the action of submitting but rather receives it. Therefore, the past participle form of the verb "submit" is required. Example: The work needs to be finished (not finish/finishing) by tonight. Meanings of other options: Option A: "submits" is the third-person singular present tense, used for active subjects. Option B: "submit" is the base form, which does not follow "to be" in a passive construction. Option C: "submitting" is the present participle, which would imply the application itself is performing an ongoing action. Information Booster: The structure $to + be + V_3$ is the st` },
  { s: `English Language`, q: `Arrange the passage correctly: (1) She poured the tea into cups through a strainer. (2) She added tea leaves, sugar, and milk to the boiling water. (3) She placed a pan of water on the stove and turned on the flame. (4) She let the mixture simmer for two minutes.`, o: [`3-2-4-1`, `2-3-4-1`, `1-3-2-4`, `3-4-2-1`], e: `The correct option is (A). Explanation The sentences describe the process of making tea. The logical order is: Sentence (3) establishes the starting point: placing the pan and turning on the heat. Sentence (2) follows: once the water is boiling, ingredients (tea leaves, sugar, milk) are added. Sentence (4) describes the next step: letting the mixture cook (simmer) to develop flavor. Sentence (1) is the concluding action: straining and serving the tea. The sequence 3-2-4-1 provides the most sensible and grammatically correct flow of instructions. So the correct answer is (a)` },
  { s: `English Language`, q: `Choose the word most similar in meaning to 'Fickle':`, o: [`Capricious`, `Devoted`, `Steadfast`, `Resolute`], e: `The correct option is (A) Capricious. Fickle: changing frequently, especially as regards one's loyalties, interests, or affection. (/) Example: The weather in the mountains can be very fickle. Capricious: given to sudden and unaccountable changes of mood or behavior. (/) Example: A capricious administration can make it difficult for businesses to plan ahead. Synonyms: Variable, Volatile, Mercurial, Unpredictable. Antonyms: Constant, Stable, Steady, Consistent. Meanings of other options: Option B: Devoted: Very loving or loyal. () Option C: Steadfast: Resolutely or dutifully firm and unwavering. () Option D: Resolute: Admirably purposeful, determined, and unwavering. ( ) So the correct answer is (a)` },
  { s: `English Language`, q: `Option C: Steadfast: Resolutely or dutifully firm and unwavering. (दृढ़) Option D: Resolute: Admirably purposeful, determined, and unwavering. (संकल्पवान)So the correct answer is (a)Option D: Resolute: Admirably purposeful, determined, and unwavering. (संकल्पवान)So the correct answer is (a) Option D: Resolute: Admirably purposeful, determined, and unwavering. (संकल्पवान) So the correct answer is (a) Option D: Resolute: Admirably purposeful, determined, and unwavering. (संकल्पवान) So the correct answer is (a)`, o: [`Agitated`, `Troubled`, `Serene`, `Restless`], e: `The correct option is (C) Serene. Perturbed: feeling anxiety or concern; unsettled or deeply disturbed. ( / ) Example: She was visibly perturbed by the news of the accident. Serene: calm, peaceful, and untroubled; tranquil. (/) Example: The lake looked beautiful and serene in the early morning light. Synonyms: Worried, Flustered, Disturbed, Upset. Antonyms: Calm, Composed, Unruffled, Serene. Meanings of other options: Option A: Agitated: Feeling or appearing troubled or nervous. () Option B: Troubled: Beset by problems or difficulties; worried. ( ) Option D: Restless: Unable to rest or relax as a result of anxiety or boredom. () So the correct answer is (c)` },
  { s: `English Language`, q: `Arrange the passage correctly: (1) He connected his laptop to the display screen using a cable. (2) He rehearsed the key points once before beginning. (3) He entered the conference hall and set up his workstation. (4) He launched the presentation software and checked each slide.`, o: [`1-3-4-2`, `3-1-4-2`, `2-1-3-4`, `3-4-1-2`], e: `The correct option is (B). Explanation The sequence follows a logical order of setting up a presentation: Sentence (3) starts the sequence by placing the person in the environment (entering the hall). Sentence (1) describes the hardware connection (laptop to screen). Sentence (4) describes the software preparation (launching the slides). Sentence (2) is the final preparatory step (rehearsing) before the actual start. The sequence 3-1-4-2 correctly reflects the step-by-step physical and technical preparation required. So the correct answer is (b)` },
  { s: `English Language`, q: `Which word is spelled correctly?`, o: [`Consciencious`, `Conscientious`, `Consciencous`, `Consientious`], e: `The correct option is (B). Conscientious is the correctly spelled word. It means wishing to do one's work or duty well and thoroughly. ( / ) Example: She is a conscientious worker who always finishes her tasks on time. Information Booster: The word is derived from "conscience" (a sense of right and wrong) + "tious" (suffix forming adjectives). Note the 't' instead of the second 'c'. So the correct answer is (b)` },
  { s: `English Language`, q: `Arrange the sentences to create a relatable classroom scenario: (1) Priya slowly rose from her seat, her eyes fixed on the floor. (2) The class fell silent the moment the teacher announced a surprise test. (3) The teacher noticed the nervousness and gave a reassuring smile. (4) "Priya, would you like to answer first?" the teacher called out.`, o: [`2-4-1-3`, `1-3-2-4`, `4-2-1-3`, `3-1-4-2`], e: `The correct option is (A). Explanation The logical flow of the classroom narrative is: Sentence (2) sets the scene and mood (announcement of the test and silence). Sentence (4) continues the action as the teacher addresses a specific student. Sentence (1) describes the student's reaction to being called on (rising nervously). Sentence (3) provides the resolution where the teacher responds to the student's visible anxiety. The sequence 2-4-1-3 builds the tension and resolves it logically. So the correct answer is (a)` },
  { s: `English Language`, q: `Fill in the blank with the most appropriate option: She always tries to look __ to her mentor for guidance.`, o: [`over`, `around`, `up`, `forward`], e: `The correct option is (C) up. Explanation The sentence requires a phrasal verb that means to admire or respect someone. "Look up to" is a common phrasal verb meaning to respect and admire someone, especially an older or more experienced person (like a mentor). ( ) Example: Many young athletes look up to him as a role mCoodpeyl.right © 2026 Adda247 Meanings of other options: Option A: "Look over" means to examine something quickly. () Option B: "Look around" means to visit a place and see what is there. ( ) Option D: "Look forward to" means to anticipate something with pleasure, but it requires the preposition "to" and an object/gerund. Information Booster: Phrasal verbs are combinations of verbs and prepositions/adverbs that have specific meanings different from the individual words. "Look` },
  { s: `English Language`, q: `What does the idiom "Break the bank" mean?`, o: [`To become bankrupt suddenly`, `To win a large amount of money`, `To cost more than one can afford`, `To take a financial risk`], e: `The correct option is (C). Break the bank: This idiom is used to describe something that costs too much money, or to say that one doesn't have enough money to buy something. ( / ) Example: You can get a good smartphone these days without breaking the bank. Other related idioms: Cost an arm and a leg: To be extremely expensive. In the red: To owe money or be in debt. So the correct answer is (c)` },
  { s: `English Language`, q: `What is the correct meaning of the idiom "Jump through hoops"?`, o: [`To celebrate a victory`, `To take shortcuts`, `To complete unnecessary acrobatic tasks`, `To do whatever is required despite difficulty`], e: `The correct option is (D). Jump through hoops: To go through a lot of effort or a series of difficult or complicated tasks to please someone or achieve a goal. ( /- ) Example: The company made me jump through hoops just to get a simple refund. Other related idioms: Go the extra mile: To do more than what is expected. Bend over backwards: To try extremely hard to help or please someone. So the correct answer is (d)` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: He carried a umbrella (1) / because the sky (2) / looked Ceoxtpryermigehlty©da2rk02(63)A/dadnad24o7vercast (4).`, o: [`He carried a umbrella (1)`, `because the sky (2)`, `looked extremely dark (3)`, `and overcast. (4)`], e: `The correct option is (A). Explanation Part (1) contains an error in the use of the indefinite article. The word "umbrella" starts with a vowel sound (uh), so it must be preceded by the article "an" instead of "a." Grammatical Rule used: The article "a" is used before words starting with a consonant sound, while "an" is used before words starting with a vowel sound (a, e, i, o, u). Example: An hour (vowel sound), A university (consonant sound 'y'). Information Booster: Always focus on the sound of the first letter, not just the letter itself. For example, "an honest man" is correct because 'h' is silent. So the correct answer is (a)` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: The coach instructed the players (1) / to practise regularly (2) / and follow (3) / each instructions carefully (4).`, o: [`The coach instructed the players (1)`, `to practise regularly (2)`, `and follow (3)`, `each instructions carefully. (4)`], e: `The correct option is (D). Explanation Part (4) of the sentence contains an error. The determiner "each" must be followed by a singular countable noun. Here, "instructions" is plural, which is grammatically incorrect. Grammatical Rule used: Distributive adjectives like "each" and "every" are always followed by singular nouns and singular verbs. Example: Each student (not students) was given a prize. Information Booster: If you wish to use a plural noun, you must use a construction like "each of the instructions" or simply "all instructions." However, "each instructions" is never correct. So the correct answer is (d)` },
  { s: `English Language`, q: `Arrange the passage correctly: (1) She boarded the cab and greeted the driver. (2) She opened the cab-booking application on her phone. (3) The cab arrived at her location within minutes. (4) She entered her destination and confirmed the booking.`, o: [`2-3-4-1`, `2-4-3-1`, `4-2-3-1`, `1-2-4-3`], e: `The correct option is (B). Explanation The correct chronological sequence for booking a cab is: Sentence (2): Opening the app is the first step. Sentence (4): Entering the destination and confirming happens after opening the app. Sentence (3): Once confirmed, the cab travels and arrives at the location. Sentence (1): Boarding the cab and greeting the driver is the final step in the sequence. The order 2-4-3-1 correctly describes the entire process flow. So the correct answer is (b)` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: This road is (1) / more wider than (2) / the one leading (3) / to the railway station (4).`, o: [`This road is (1)`, `more wider than (2)`, `the one leading (3)`, `to the railway station. (4)`], e: `The correct option is (B). Explanation Part (2) contains an error of "double comparatives." The word "wider" is already in the comparative degree. Adding "more" before it is redundant and grammatically incorrect. Grammatical Rule used: Avoid using double comparatives or double superlatives. If an adjective forms its comparative by adding "-er," do not use "more." If it uses "more," do not add "-er." Example: Correct: taller, faster, more beautiful. Incorrect: more taller, more faster. Information Booster: Similarly, avoid "most wisest" or "most tallest." Use only one marker of the degree. So the correct answer is (b)` },
  { s: `English Language`, q: `Fill in the blank with the most appropriate option: The lecturer explained the concept so __________ that the audience grew restless.`, o: [`tedious`, `tediously`, `tediousness`, `tedium`], e: `The correct option is (B) tediously. Explanation The blank requires an adverb to describe the manner in which the lecturer "explained" (a verb). "Tediously" is the adverbial form meaning in a bored or tiresome way. ( ) Example: The data was entered tediously into the system. Meanings of other options: Option A: "tedious" is an adjective (used to describe nouns). Option C: "tediousness" is a noun. Option D: "tedium" is a noun meaning the state of being tedious. Information Booster: Adverbs of manner often end in "-ly" and answer the question "How?". In this sentence, the audience's restlessness confirms that the manner of explanation was the issue. So the correct answer is (b)` },
  { s: `English Language`, q: `Pick the correctly spelled word:`, o: [`Acreagge`, `Acreage`, `Accreage`, `Aceerage`], e: `The correct option is (B). Acreage is the correctly spelled word. It refers to an area of land, typically when used for agricultural purposes, measured in acres. (/ ) Example: The farmer decided to increase his acreage of corn this year. Meanings of other options: Option A: Incorrect spelling (double 'g'). Option C: Incorrect spelling (double 'c'). Option D: Incorrect spelling (wrong vowel placement). Information Booster: The word is formed by adding the suffix "-age" to "acre." Unlike some other words ending in 'e', the 'e' in acre is retained before the suffix. So the correct answer is (b)` },
  { s: `English Language`, q: `Choose the correct one-word substitution for: "Published or existing after the death of the person who created it."`, o: [`Legacy`, `Memorial`, `Posthumous`, `Ancestral`], e: `The correct option is (C). The correct one-word for the given group of words is Posthumous. It refers to something that occurs, is awarded, or is published after the death of the originator. () Example: The soldier was awarded a posthumous medal for his bravery. Meanings of other options: Legacy: An amount of money or property left to someone in a will. () Memorial: A structure or event established to remind people of a person or event. () Ancestral: Belonging to or inherited from one's ancestors. () So the correct answer is (c)` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: The children plays (1) / happily in the park (2) / every evening (3) / after school (4).`, o: [`The children plays (1)`, `happily in the park (2)`, `every evening (3)`, `after school. (4)`], e: `The correct option is (A). Explanation Part (1) contains a subject-verb agreement error. "Children" is the plural form of "child." According to the rules of present simple tense, a plural subject must be followed by a plural verb (base form without 's'). Therefore, "plays" should be replaced with "play." Grammatical Rule used: Singular subjects take singular verbs (V + s/es), and plural subjects take plural verbs (V1). Example: The child plays. The children play. Information Booster: Irregular plurals like children, men, women, and teeth often confuse students. Always identify the base singular form to determine if the subject is plural. So the correct answer is (a)` },
  { s: `English Language`, q: `Grammatical Rule used: Singular subjects take singular verbs (V + s/es), and plural subjects take plural verbs (V1). Example: The child plays. The children play. Information Booster: Irregular plurals like children, men, women, and teeth often confuse students. Always identify the base singular form to determine if the subject is plural. So the correct answer is (a)`, o: [`Zealous`, `Apathetic`, `Fervent`, `Motivated`], e: `The correct option is (B) Apathetic. Eager: strongly wanting to do or have something; showing keen interest. (/) Example: The students were eager to learn about the new project. Apathetic: showing or feeling no interest, enthusiasm, or concern. () Example: Voters are becoming increasingly apathetic about local politics. Synonyms: Enthusiastic, Keen, Avid, Anxious. Antonyms: Indifferent, Uninterested, Apathetic, Unmoved. Meanings of other options: Option A: Zealous: Having or showing great energy or enthusiasm. ( ) Option C: Fervent: Having or displaying a passionate intensity. ( ) Option D: Motivated: Provided with a reason or incentive to act. ( ) So the correct answer is (b)` },
  { s: `English Language`, q: `Choose the word most similar in meaning to 'Lackluster':`, o: [`Radiant`, `Spirited`, `Mediocre`, `Vibrant`], e: `The correct option is (C) Mediocre. Lackluster: lacking in vitality, force, or conviction; uninspired or uninspiring. (/) Example: The team gave a lackluster performance in the first half of the game. Mediocre: of only moderate quality; not very good. ( ) Example: The film was mediocre, despite having a great cast. Synonyms: Dull, Uninspired, Drab, Flat. Antonyms: Brilliant, Exceptional, Shining, Radiant. Meanings of other options: Option A: Radiant: Sending out light; shining or glowing brightly. () Option B: Spirited: Full of energy, enthusiasm, and determination. () Option D: Vibrant: Full of energy and life. () So the correct answer is (c)` },
  { s: `English Language`, q: `Choose the correct one-word substitution for: "The slow ringing of a bell to announce a death or funeral."`, o: [`Chime`, `Clang`, `Peal`, `Knell`], e: `The correct option is (D). The correct one-word for the given group of words is Knell. It specifically refers to the sound of a bell rung slowly to signify a death or funeral. (- ) Example: The distant knell of the church bell announced the passing of the village elder. Meanings of other options: Chime: A melodious ringing sound, often from a clock. () Clang: A loud, resonant metallic sound. (/) Peal: A loud prolonged sound of thunder or a set of bells. () So the correct answer is (d)` }
];

if (RAW.length !== 100) { console.error(`Expected 100 questions, got ${RAW.length}`); process.exit(1); }

async function seed() {
  console.log('Connecting to MongoDB...');
  await mongoose.connect(MONGO_URI);
  console.log('Connected.');

  let category = await ExamCategory.findOne({ name: 'Central', type: 'Central' });
  if (!category) {
    category = await ExamCategory.create({ name: 'Central', type: 'Central', description: 'Central government competitive exams' });
  }

  let exam = await Exam.findOne({ code: 'SSC-SSP-MAT' });
  if (!exam) {
    exam = await Exam.create({
      category: category._id,
      name: 'SSC Selection Post (Matriculation Level)',
      code: 'SSC-SSP-MAT',
      description: 'Staff Selection Commission - Selection Post (Matriculation Level)',
      isActive: true
    });
  }

  const PATTERN_TITLE = 'SSC Selection Post (Matriculation Level)';
  let pattern = await ExamPattern.findOne({ exam: exam._id, title: PATTERN_TITLE });
  if (!pattern) {
    pattern = await ExamPattern.create({
      exam: exam._id, title: PATTERN_TITLE, duration: 60, totalMarks: 200, negativeMarking: 0.5,
      sections: [
        { name: REA, totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: GA,  totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: QA,  totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: ENG, totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 }
      ]
    });
  }

  const TEST_TITLE = 'SSC Selection Post (Matriculation) - 28 July 2025 Shift-1 [Similar Paper]';
  await PracticeTest.deleteMany({ examPattern: pattern._id, title: TEST_TITLE });

  const questions = RAW.map((r, i) => ({
    questionText: r.q,
    questionImage: '',
    options: r.o,
    optionImages: ['', '', '', ''],
    correctAnswerIndex: KEY[i] - 1,
    explanation: r.e || '',
    section: r.s,
    tags: ['SSC', 'Selection Post', 'Phase XIII', 'Matriculation', 'PYQ', '2025', 'Similar Paper'],
    difficulty: 'medium'
  }));

  const test = await PracticeTest.create({
    examPattern: pattern._id, title: TEST_TITLE, totalMarks: 200, duration: 60,
    accessLevel: 'FREE', isPYQ: true, pyqYear: 2025, pyqShift: '1',
    pyqExamName: 'SSC Selection Post Phase XIII (Matriculation) - Similar Paper', questions
  });
  console.log(`Created PYQ PracticeTest: ${test._id} (${test.questions.length} questions)`);

  await mongoose.disconnect();
  console.log('Done.');
}

seed().catch(err => { console.error('Seed failed:', err); process.exit(1); });
